"use client";

import { useEffect, useRef } from "react";

interface NetNode {
  stage: number;
  idx: number;
  x: number;
  y: number;
  z: number;
  act: number;
  twinkle: number;
}

interface NetEdge {
  a: NetNode;
  b: NetNode;
  w: number;
  tw: number;
  kind: "attn" | "ffn" | "skip";
  ctrlX: number;
  ctrlY: number;
  ctrlZ: number;
}

// Transformer-style block in 3D: tokens -> attention -> FFN -> output.
//   stage 0: token embeddings         (6)
//   stage 1: attention output         (6)  -- self-attention (6x6)
//   stage 2: FFN hidden               (12) -- 6->12
//   stage 3: block output             (6)  -- 12->6
// Two residual connections (same-index, arced out-of-plane):
//   skip A: stage 0 -> stage 2  (around attention+FFN input)
//   skip B: stage 1 -> stage 3  (around FFN)
const STAGE_SIZES = [6, 6, 12, 6];
const NUM_STAGES = STAGE_SIZES.length;
const N_TOK = STAGE_SIZES[0];

// Attention pattern templates applied to the stage0->stage1 edges.
const PATTERNS: Array<(i: number, j: number) => number> = [
  (i, j) => Math.exp(-Math.abs(i - j) / 1.6), // local window
  (i, j) => (i === j ? 0.95 : 0.28 + 0.12 * ((i + j) % 3)), // mixed diagonal
  (i, j) => (j >= i ? Math.exp(-(j - i) / 2.2) : 0.14), // causal-forward
  (i, j) => (j <= i ? Math.exp(-(i - j) / 2.2) : 0.14), // causal-backward
  (i, j) => Math.exp(-((i - j - 2) ** 2) / 2.4), // shifted peak
  (i, j) => 0.4 + 0.5 * Math.abs(Math.sin((i + 1) * (j + 1) * 0.7)), // global
];

// Single muted slate-blue family. Variation is by alpha only.
const C = {
  edge: "hsl(205, 22%, 52%)",
  skip: "hsl(205, 16%, 44%)",
  pulse: "hsl(200, 30%, 64%)",
  node: "hsl(205, 24%, 58%)",
  pos: "hsl(205, 20%, 50%)",
};
const DASH = [3, 4];
const TAU = Math.PI * 2;

// Camera parameters (world units are roughly screen pixels at depth 0).
const CAM_TILT = -0.38; // X-axis tilt (radians) — look down slightly
const FOCAL = 900;
const CAM_Z = 760;

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    let nodes: NetNode[][] = [];
    let edges: NetEdge[] = [];
    let posPoints: Array<{ x: number; y: number; z: number }> = [];
    let runStart = performance.now();
    let nextReset = 30 + Math.random() * 14;
    let cycle = 0;
    let patIdx = Math.floor(Math.random() * PATTERNS.length);

    // Calm pacing: slow attention + FFN sweeps, then a soft settle.
    const ATTN_DUR = 2.8;
    const FFN_DUR = 2.8;
    const SETTLE_DUR = 1.3;
    const CYCLE_DUR = ATTN_DUR + FFN_DUR + SETTLE_DUR;

    const randn = () =>
      (Math.random() + Math.random() + Math.random() - 1.5) * 0.5;

    // World layout constants (set on resize).
    let stageSpacingX = 130;
    let stageZSpread = 180;
    let nodeSpacingY = 20;
    let layoutCy = 0;

    // 3D point → screen. Rotation: Y-axis spin + fixed X-axis tilt.
    const project = (wx: number, wy: number, wz: number, rotY: number) => {
      // Y-axis rotation
      const cy = Math.cos(rotY);
      const sy = Math.sin(rotY);
      const rx = wx * cy - wz * sy;
      const rz = wx * sy + wz * cy;
      // X-axis tilt
      const ct = Math.cos(CAM_TILT);
      const st = Math.sin(CAM_TILT);
      const ty = wy * ct - rz * st;
      const tz = wy * st + rz * ct;
      // perspective
      const denom = CAM_Z + tz;
      const safeDenom = denom > 1 ? denom : 1;
      const scale = FOCAL / safeDenom;
      return {
        sx: width / 2 + rx * scale,
        sy: layoutCy + ty * scale,
        depth: tz,
        scale,
      };
    };

    const buildNetwork = () => {
      nodes = [];
      edges = [];
      posPoints = [];

      const availW = width - 280;
      stageSpacingX = Math.max(120, Math.min(160, availW / (NUM_STAGES - 1)));
      stageZSpread = Math.min(200, stageSpacingX * 1.3);
      const maxNodes = Math.max(...STAGE_SIZES);
      const availH = height * 0.78;
      nodeSpacingY = Math.min(18, availH / (maxNodes - 1));
      layoutCy = height * 0.5;

      for (let s = 0; s < NUM_STAGES; s++) {
        const n = STAGE_SIZES[s];
        const stageNodes: NetNode[] = [];
        const wx = (s - (NUM_STAGES - 1) / 2) * stageSpacingX;
        // Stagger stages in Z for depth.
        const wz = (s - (NUM_STAGES - 1) / 2) * stageZSpread * 0.45;
        const startY = -((n - 1) / 2) * nodeSpacingY;
        for (let i = 0; i < n; i++) {
          stageNodes.push({
            stage: s,
            idx: i,
            x: wx,
            y: startY + i * nodeSpacingY,
            z: wz,
            act: 0,
            twinkle: Math.random() * TAU,
